const raw = $input.first().json.content;

let aulaJson;
try {
  // Tenta parsear direto
  aulaJson = JSON.parse(raw);
} catch (e) {
  // Extrai JSON de dentro de blocos markdown se necessário
  const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    aulaJson = JSON.parse(match[1].trim());
  } else {
    // Tenta extrair o objeto JSON manualmente
    const start = raw.indexOf('{');
    const end = raw.lastIndexOf('}');
    aulaJson = JSON.parse(raw.substring(start, end + 1));
  }
}

return [{ json: aulaJson }];
